// Validate and process incoming route space order
const body = $input.first().json.body;

// Required fields
const required = ['business_name', 'contact_name', 'contact_email', 'route_id', 'slot_number'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  return [{
    json: {
      success: false,
      error: `Missing required fields: ${missing.join(', ')}`,
      status: 400
    }
  }];
}

return [{
  json: {
    success: true,
    business_name: body.business_name,
    contact_name: body.contact_name,
    contact_email: body.contact_email,
    contact_phone: body.phone || '',
    route_id: body.route_id,
    slot_number: parseInt(body.slot_number),
    ad_description: body.ad_description || '',
    price: parseFloat(body.price) || 550.00
  }
}];

const space = $input.first().json;
const order = $('Validate Order').first().json;

if (!space || !space.id) {
  return [{
    json: {
      success: false,
      error: 'This space is no longer available. Please select a different space.',
      status: 409
    }
  }];
}

return [{
  json: {
    ...order,
    space_id: space.id,
    space_type: space.space_type,
    route_id: order.route_id,
    reserved_until: new Date(Date.now() + 48 * 60 * 60 * 1000).toISOString()
  }
}];

// Create Stripe checkout session URL
const space = $('Check Availability').first().json;
const routeInfo = $input.first().json[0];

// For now, return a placeholder — replace with actual Stripe integration
const stripeLink = `https://buy.stripe.com/YOUR_STRIPE_LINK?client_reference_id=${space.space_id}`;

return [{
  json: {
    success: true,
    space_id: space.space_id,
    slot_number: space.slot_number,
    space_type: space.space_type,
    route_number: routeInfo.route_number,
    zip_code: routeInfo.zip_code,
    city: routeInfo.city,
    state: routeInfo.state_code,
    business_name: space.business_name,
    price: space.price,
    reserved_until: space.reserved_until,
    payment_url: stripeLink,
    message: `Space #${space.slot_number} (${space.space_type}) reserved for ${space.business_name} in Route ${routeInfo.route_number} (${routeInfo.zip_code}). Payment due within 48 hours.`
  }
}];
